"""
Critic2 Adapter
critic2 量子化学分析工具适配器
"""

from pathlib import Path
from typing import Dict, Any, Optional, List
import shutil
from loguru import logger

from .base_adapter import ExternalAdapter, InputBundle, RunResult, ParsedResult, ExternalResult
from ..bridge_context import BridgeContext
from ..executor import ExecutionResult


class Critic2Adapter(ExternalAdapter):
    """
    critic2 适配器
    
    支持的分析类型：
    - qtaim: QTAIM Bader 分析
    """
    
    DEFAULT_CONFIG = {
        "executable": "critic2",
        "timeout_seconds": 300,
        "working_directory": "bridges/critic2",
        "analysis_type": "qtaim",
        "enable_debug_mode": False,
        "qtaim_options": {
            "max_iter": 100,
            "conv_tol": 1e-5,
        }
    }
    
    def __init__(self, config: Optional[Dict[str, Any]] = None):
        merged_config = {**self.DEFAULT_CONFIG, **(config or {})}
        super().__init__(merged_config)
        
        self.analysis_type = self.config["analysis_type"]
        self.working_dir = Path(self.config["working_directory"])
    
    def prepare_inputs(self, context: BridgeContext) -> InputBundle:
        """
        准备 critic2 输入文件
        
        生成 critic2.in 脚本，使用绝对路径引用 cube 文件
        """
        # 创建工作目录
        work_dir = self.working_dir / context.molecule_id
        work_dir.mkdir(parents=True, exist_ok=True)
        
        input_file = work_dir / "critic2.in"
        output_file = work_dir / "critic2.out"
        xyz_file = work_dir / "molecule.xyz"
        
        # 验证 density cube 存在
        density_cube = Path(context.density_cube_path)
        if not density_cube.exists():
            raise FileNotFoundError(f"Density cube not found: {density_cube}")
        
        # 生成分子 xyz（angstrom）
        self._write_xyz(context, xyz_file)

        # 生成输入脚本
        script_lines = self._generate_script(context, density_cube, xyz_file)
        
        # 写入输入文件
        with open(input_file, 'w') as f:
            f.write('\n'.join(script_lines))
        
        logger.debug(f"Generated critic2 input: {input_file}")
        
        return InputBundle(
            input_file=input_file,
            output_file=output_file,
            working_directory=work_dir,
            auxiliary_files=[density_cube, xyz_file],
            command_args=[str(input_file)],
        )
    
    def _write_xyz(self, context: BridgeContext, xyz_file: Path) -> None:
        """写入 xyz 文件，供 critic2 molecule 语句使用"""
        with open(xyz_file, "w") as f:
            f.write(f"{context.natm}\n")
            f.write(f"{context.molecule_id} generated by FastORCA Critic2Adapter\n")
            for sym, coord in zip(context.atom_symbols, context.atom_coords_angstrom):
                f.write(
                    f"{sym} "
                    f"{float(coord[0]):.10f} "
                    f"{float(coord[1]):.10f} "
                    f"{float(coord[2]):.10f}\n"
                )

    def _generate_script(self, context: BridgeContext, density_cube: Path, xyz_file: Path) -> List[str]:
        """生成 critic2 输入脚本"""
        lines = [
            f"# Critic2 input for {context.molecule_id}",
            f"# Generated by FastORCA Critic2Adapter",
            f"# Analysis type: {self.analysis_type}",
            "",
        ]
        
        if self.analysis_type == "qtaim":
            lines.extend(self._generate_qtaim_script(density_cube, xyz_file))
        else:
            raise ValueError(f"Unknown analysis type: {self.analysis_type}")
        
        return lines
    
    def _generate_qtaim_script(self, density_cube: Path, xyz_file: Path) -> List[str]:
        """生成 QTAIM 分析脚本"""
        lines = [
            f"# Load molecular geometry first (required by critic2 before load/qtaim)",
            # Use explicit format keyword for compatibility with older/dev critic2 parsers.
            f"molecule xyz {xyz_file.absolute()}",
            "",
            f"# Load density cube with absolute path",
            f"load {density_cube.absolute()} id rho",
            "",
            "# Avoid Laplacian integration on non-periodic grid (can trigger FFT periodic-cell error)",
            "prop_mode 1",
            "",
            "# Output atomic properties (Bader integration)",
            "bader",
            "",
        ]
        return lines
    
    def run_external(self, input_bundle: InputBundle) -> RunResult:
        """执行 critic2"""
        # 初始化执行器
        self._init_executor(
            executable=self.config["executable"],
            timeout=self.config["timeout_seconds"],
            cwd=str(input_bundle.working_directory),
        )
        
        # 检查可执行文件
        if not self.executor.check_executable():
            raise FileNotFoundError(f"critic2 executable not found: {self.config['executable']}")
        
        # 执行（兼容性模式）
        # 对部分 critic2 构建，`critic2 input.in` 会直接 STOP 1，
        # 但 `critic2 < input.in` 可稳定运行，因此改为 stdin 喂入脚本。
        with open(input_bundle.input_file, "r") as f:
            script_text = f.read()
        exec_result = self.executor.execute(args=[], input_text=script_text)
        
        # 保存输出到文件
        with open(input_bundle.output_file, 'w') as f:
            f.write(exec_result.stdout)
            if exec_result.stderr:
                f.write("\n# STDERR\n")
                f.write(exec_result.stderr)
        
        return RunResult(
            execution_result=exec_result,
            output_files=[input_bundle.output_file],
        )
    
    def parse_outputs(self, run_result: RunResult) -> ParsedResult:
        """
        解析 critic2 输出
        
        解析 QTAIM Bader 电荷和体积
        """
        output_file = run_result.output_files[0]
        
        if not output_file.exists():
            raise FileNotFoundError(f"Output file not found: {output_file}")
        
        with open(output_file, 'r') as f:
            content = f.read()
        
        # 解析 Bader 电荷和体积
        features = self._parse_bader_analysis(content)
        
        # 提取版本信息
        version = self._parse_version(content)
        
        # 检查警告
        warnings = self._extract_warnings(content)
        
        return ParsedResult(
            features=features,
            metadata={
                "tool_version": version,
                "analysis_type": self.analysis_type,
                "output_file_size": len(content),
            },
            warnings=warnings,
        )
    
    def _parse_bader_analysis(self, content: str) -> Dict[str, Any]:
        """
        解析 Bader 分析结果
        
        提取：
        - bader_charges
        - bader_volumes
        - n_bader_volumes (验证用)
        """
        features = {
            "qtaim": {
                "bader_charges": None,
                "bader_volumes": None,
                "n_bader_volumes": 0,
            }
        }
        
        lines = content.split('\n')
        
        bader_charges = []
        bader_volumes = []
        
        # 查找 Bader 分析表格
        # critic2 输出格式示例：
        # # Atomic properties
        # # Id   Z   Name   Population   Volume
        #    1   8   O      9.2345       45.234
        #    2   1   H      0.3827       12.123
        
        in_bader_table = False
        
        for i, line in enumerate(lines):
            # 检测 Bader 表格开始
            if "Atomic properties" in line or "Bader" in line:
                in_bader_table = True
                continue
            
            if not in_bader_table:
                continue
            
            # 跳过表头行
            if "Id" in line and "Population" in line:
                continue
            
            # 尝试解析数据行
            parts = line.split()
            if len(parts) >= 5:
                try:
                    # 尝试解析数字
                    atom_id = int(parts[0])
                    z = int(parts[1])
                    name = parts[2]
                    population = float(parts[3])
                    volume = float(parts[4])
                    
                    # Bader 电荷 = Z - Population
                    charge = z - population
                    
                    bader_charges.append(charge)
                    bader_volumes.append(volume)
                    
                except (ValueError, IndexError):
                    # 不是数据行
                    if len(bader_charges) > 0:
                        # 已经解析了一些数据，遇到非数据行表示结束
                        break
                    continue
            elif len(bader_charges) > 0 and line.strip() == "":
                # 空行表示表格结束
                break
        
        if bader_charges:
            features["qtaim"]["bader_charges"] = bader_charges
            features["qtaim"]["bader_volumes"] = bader_volumes
            features["qtaim"]["n_bader_volumes"] = len(bader_volumes)
            logger.info(f"Parsed {len(bader_charges)} Bader volumes")
        else:
            logger.warning("No Bader data found in output")
        
        return features
    
    def _parse_version(self, content: str) -> Optional[str]:
        """解析 critic2 版本"""
        # 查找版本信息行
        for line in content.split('\n'):
            if "critic2" in line.lower() and "version" in line.lower():
                # 尝试提取版本号
                parts = line.split()
                for i, part in enumerate(parts):
                    if "version" in part.lower() and i + 1 < len(parts):
                        return parts[i + 1]
        return None
    
    def _extract_warnings(self, content: str) -> List[str]:
        """提取警告信息"""
        warnings = []
        for line in content.split('\n'):
            if "warning" in line.lower():
                warnings.append(line.strip())
        return warnings


def run_critic2_analysis(
    context: BridgeContext,
    config: Optional[Dict[str, Any]] = None
) -> ExternalResult:
    """
    便捷函数：运行 critic2 分析
    
    Args:
        context: 桥接上下文
        config: 可选配置
        
    Returns:
        ExternalResult
    """
    adapter = Critic2Adapter(config)
    return adapter.execute(context)
